+    #[test]
+    fn test_mcp_tools_collection() {
+        let tools = collect_mcp_tools();
+        assert!(!tools.is_empty());
+        assert!(tools.iter().any(|t| t.name == "search"));
+        assert!(tools.iter().any(|t| t.name == "lint"));
